import{_ as e}from"./chunks/cloudflare api token截图.cXTahxtC.js";import{_ as l}from"./chunks/查看全局令牌.BhcACLhK.js";import{_ as o,o as i,c as r,a2 as t}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Cloudflare API Token","description":"","frontmatter":{},"headers":[],"relativePath":"ru-RU/Safety/cloudflare-api-token.md","filePath":"ru-RU/Safety/cloudflare-api-token.md","lastUpdated":1781962217000}'),d={name:"ru-RU/Safety/cloudflare-api-token.md"};function n(p,a,u,c,h,s){return i(),r("div",null,[...a[0]||(a[0]=[t('<h1 id="cloudflare-api-token" tabindex="-1">Cloudflare API Token <a class="header-anchor" href="#cloudflare-api-token" aria-label="Permalink to &quot;Cloudflare API Token&quot;">​</a></h1><p>Учетные данные Cloudflare API позволяют ImgBed очищать кеш Cloudflare CDN после изменений файлов.</p><p><img src="'+e+'" alt="Настройки Cloudflare API Token" loading="lazy"></p><h2 id="где-это-настраивается" tabindex="-1">Где это настраивается <a class="header-anchor" href="#где-это-настраивается" aria-label="Permalink to &quot;Где это настраивается&quot;">​</a></h2><p>Откройте админ-панель и перейдите в:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Cloudflare API Token</span></span></code></pre></div><p>Нужно заполнить:</p><ul><li>Zone ID</li><li>Account email</li><li>API Key</li></ul><h2 id="что-делает-эта-настроика" tabindex="-1">Что делает эта настройка <a class="header-anchor" href="#что-делает-эта-настроика" aria-label="Permalink to &quot;Что делает эта настройка&quot;">​</a></h2><p>Cloudflare может кешировать публичные URL изображений.</p><p>Кеш ускоряет доставку изображений, но после удаления, блокировки, замены или перемещения файла старое содержимое может еще некоторое время оставаться видимым.</p><p>После настройки учетных данных Cloudflare API ImgBed пытается очистить связанный кеш Cloudflare, когда такие операции завершаются.</p><p>Это полезно, если:</p><ul><li>вы удаляете изображение и хотите, чтобы публичная ссылка перестала работать как можно быстрее;</li><li>вы блокируете изображение и хотите, чтобы посетители больше не видели исходный файл;</li><li>вы заменяете файл с тем же именем и хотите быстрее показать посетителям новую версию;</li><li>вы перемещаете или переименовываете файлы и хотите быстро обновить кеш старых путей;</li><li>вы меняете правила публичного доступа и хотите быстрее обновить кеш публичной галереи или random image API.</li></ul><h2 id="что-будет-если-оставить-пустым" tabindex="-1">Что будет, если оставить пустым <a class="header-anchor" href="#что-будет-если-оставить-пустым" aria-label="Permalink to &quot;Что будет, если оставить пустым&quot;">​</a></h2><p>ImgBed продолжит работать нормально без этой настройки.</p><p>Единственная разница: ImgBed не будет активно очищать кеш Cloudflare CDN. Посетители могут видеть старый контент, пока кеш Cloudflare не истечет естественным образом.</p><h2 id="как-наити-zone-id" tabindex="-1">Как найти Zone ID <a class="header-anchor" href="#как-наити-zone-id" aria-label="Permalink to &quot;Как найти Zone ID&quot;">​</a></h2><p>Zone ID — это Cloudflare Zone ID сайта, который используется вашим доменом ImgBed.</p><ol><li>Войдите в Cloudflare dashboard.</li><li>Откройте сайт, где находится домен ImgBed.</li><li>Найдите <code>Zone ID</code> на overview-странице сайта.</li><li>Скопируйте его в поле <code>Zone ID</code> в ImgBed.</li></ol><p>Это именно Zone ID сайта, а не account ID.</p><h2 id="account-email" tabindex="-1">Account Email <a class="header-anchor" href="#account-email" aria-label="Permalink to &quot;Account Email&quot;">​</a></h2><p>Введите email, который используете для входа в Cloudflare.</p><p>Он должен соответствовать API Key, который вы укажете ниже.</p><h2 id="api-key" tabindex="-1">API Key <a class="header-anchor" href="#api-key" aria-label="Permalink to &quot;API Key&quot;">​</a></h2><p>Введите Cloudflare Global API Key.</p><ol><li>Войдите в Cloudflare dashboard.</li><li>Откройте свой profile.</li><li>Перейдите на страницу API Tokens.</li><li>Найдите <code>Global API Key</code>.</li><li>Просмотрите и скопируйте его.</li><li>Вставьте его в поле <code>API Key</code> в ImgBed.</li></ol><p><img src="'+l+'" alt="Просмотр global API key" loading="lazy"></p><h2 id="когда-это-начинает-работать" tabindex="-1">Когда это начинает работать <a class="header-anchor" href="#когда-это-начинает-работать" aria-label="Permalink to &quot;Когда это начинает работать&quot;">​</a></h2><p>После заполнения полей сохраните настройки.</p><p>Будущие изменения файлов автоматически будут пытаться очистить кеш Cloudflare. Прошлые операции не очищаются задним числом. Если файл был удален или заменен до настройки, дождитесь истечения кеша Cloudflare или очистите его вручную в Cloudflare.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="это-обязательно" tabindex="-1">Это обязательно? <a class="header-anchor" href="#это-обязательно" aria-label="Permalink to &quot;Это обязательно?&quot;">​</a></h3><p>Нет.</p><p>Если ваш домен не использует Cloudflare или вас не беспокоит задержка CDN-кеша, поле можно оставить пустым.</p><h3 id="неправильные-учетные-данные-сломают-загрузку" tabindex="-1">Неправильные учетные данные сломают загрузку? <a class="header-anchor" href="#неправильные-учетные-данные-сломают-загрузку" aria-label="Permalink to &quot;Неправильные учетные данные сломают загрузку?&quot;">​</a></h3><p>Обычно нет.</p><p>Неправильные учетные данные только помешают ImgBed очищать кеш Cloudflare. Загрузка и обычный доступ к файлам должны продолжить работать.</p><h3 id="почему-удаленное-изображение-все-еще-открывается" tabindex="-1">Почему удаленное изображение все еще открывается? <a class="header-anchor" href="#почему-удаленное-изображение-все-еще-открывается" aria-label="Permalink to &quot;Почему удаленное изображение все еще открывается?&quot;">​</a></h3><p>Самая частая причина — Cloudflare все еще держит старый файл в кеше.</p><p>С правильными учетными данными Cloudflare API ImgBed очищает кеш связанного URL при удалении файла.</p><h3 id="почему-после-замены-фаила-я-все-еще-вижу-старое-изображение" tabindex="-1">Почему после замены файла я все еще вижу старое изображение? <a class="header-anchor" href="#почему-после-замены-фаила-я-все-еще-вижу-старое-изображение" aria-label="Permalink to &quot;Почему после замены файла я все еще вижу старое изображение?&quot;">​</a></h3><p>Это тоже обычно связано с CDN-кешем.</p><p>После настройки этого параметра ImgBed пытается очистить кеш старого URL, когда файл с тем же именем перезаписывается.</p>',44)])])}const P=o(d,[["render",n]]);export{b as __pageData,P as default};
